What does the following program print?

```cpp
#include <random>
#include <iostream>
std::mt19937 rng{ 7u };
int pick(int lo, int hi)
{
    std::uniform_int_distribution<int> d{ lo, hi };
    return d(rng);
}
int main()
{
    std::cout << pick(1, 5) << '\n';
    std::cout << pick(1, 5) << '\n';
}
```

The code below is supposed to let `rollDie()` share a single engine with `main()`, but it has a scoping bug. What is wrong?

```cpp
#include <random>
#include <iostream>
int rollDie()
{
    std::uniform_int_distribution<int> d{ 1, 6 };
    return d(rng);  // refers to rng
}
int main()
{
    std::mt19937 rng{ 42u };  // engine defined here
    std::cout << rollDie() << '\n';
}
```

